/* DC Hub Analytics v70 - GA4: G-EHS23WT5R6 */
(function(){'use strict';const A={config:{ga4Id:'G-EHS23WT5R6',debug:false},session:{id:null,startTime:null,pageViews:0,chatMessages:0,scrollDepthMax:0},init(){this.initSession();this.trackPageView();this.setupScrollTracking();this.setupEventListeners();this.setupErrorTracking();this.patchChatbot();if(this.config.debug)console.log('📊 DC Hub Analytics v70 initialized');},initSession(){let s=sessionStorage.getItem('dchub_session');if(s){const p=JSON.parse(s);if(Date.now()-p.startTime<1800000){this.session=p;this.session.pageViews++;this.saveSession();return;}}this.session={id:'dchub_'+Date.now().toString(36)+Math.random().toString(36).substr(2,9),startTime:Date.now(),pageViews:1,chatMessages:0,scrollDepthMax:0,referrer:document.referrer||'direct',landingPage:window.location.pathname,device:this.getDevice()};this.saveSession();this.track('session_start',{referrer:this.session.referrer,landing_page:this.session.landingPage,device:this.session.device});},saveSession(){sessionStorage.setItem('dchub_session',JSON.stringify(this.session));},getDevice(){const u=navigator.userAgent;if(/(tablet|ipad|playbook|silk)|(android(?!.*mobi))/i.test(u))return'tablet';if(/Mobile|Android|iP(hone|od)|IEMobile|BlackBerry|Kindle/.test(u))return'mobile';return'desktop';},track(e,p={}){if(typeof gtag==='function')gtag('event',e,p);if(this.config.debug)console.log('📊',e,p);},trackPageView(){this.track('page_view',{page_title:document.title,page_path:window.location.pathname});},patchChatbot(){const check=setInterval(()=>{if(typeof DCHubChat!=='undefined'){clearInterval(check);this.enhanceChatbot();}},100);setTimeout(()=>clearInterval(check),10000);},enhanceChatbot(){const self=this,chat=DCHubChat;const origOpen=chat.open.bind(chat),origClose=chat.close.bind(chat),origSend=chat.send.bind(chat),origQuick=chat.quickAsk.bind(chat),origLead=chat.submitLead.bind(chat),origSkip=chat.skipLead.bind(chat);chat.open=function(){const r=origOpen();self.track('chatbot_open',{session_messages:self.session.chatMessages,time_on_page:Math.round((Date.now()-self.session.startTime)/1000)});return r;};chat.close=function(){const r=origClose();self.track('chatbot_close',{messages:self.session.chatMessages});return r;};chat.send=async function(){const input=document.getElementById('dchub-chat-input');const msg=input?input.value.trim():'';const start=Date.now();const r=await origSend();self.session.chatMessages++;self.saveSession();self.track('chatbot_message_sent',{message_length:msg.length,message_number:self.session.chatMessages});self.track('chatbot_response',{response_time_ms:Date.now()-start});return r;};chat.quickAsk=function(q){let cat='other';if(q.toLowerCase().includes('market'))cat='markets';else if(q.toLowerCase().includes('pricing'))cat='pricing';else if(q.toLowerCase().includes('site'))cat='site_selection';else if(q.toLowerCase().includes('demo'))cat='demo_request';self.track('chatbot_quick_action',{action:q,category:cat});return origQuick(q);};chat.submitLead=function(){const email=document.getElementById('dchub-lead-email')?.value||'';self.track('chatbot_lead_capture',{email_domain:email.split('@')[1]||'unknown',messages_before:self.session.chatMessages,time_to_capture:Math.round((Date.now()-self.session.startTime)/1000)});if(typeof gtag==='function')gtag('event','conversion',{send_to:'G-EHS23WT5R6',event_category:'lead'});return origLead();};chat.skipLead=function(){self.track('chatbot_lead_skip',{messages:self.session.chatMessages});return origSkip();};console.log('📊 Chatbot tracking enhanced');},setupScrollTracking(){let ticking=false;const thresholds=[25,50,75,90,100],tracked=new Set();window.addEventListener('scroll',()=>{if(!ticking){requestAnimationFrame(()=>{const h=document.documentElement.scrollHeight-window.innerHeight;const pct=Math.min(Math.round(window.scrollY/h*100),100);if(pct>this.session.scrollDepthMax){this.session.scrollDepthMax=pct;this.saveSession();}thresholds.forEach(t=>{if(pct>=t&&!tracked.has(t)){tracked.add(t);this.track('scroll_depth',{depth:t});}});ticking=false;});ticking=true;}},{passive:true});},setupEventListeners(){document.addEventListener('click',e=>{const pricing=e.target.closest('[id*="pricing"],[class*="pricing"]');if(pricing)this.track('pricing_click',{element:pricing.id||pricing.className});const facility=e.target.closest('.facility-card');if(facility)this.track('facility_view',{name:facility.querySelector('.facility-name')?.textContent||'unknown'});const cta=e.target.closest('.hero-btn,.btn-primary,.btn-green');if(cta)this.track('cta_click',{text:cta.textContent.trim().substring(0,30)});const outbound=e.target.closest('a[href^="http"]');if(outbound&&!outbound.href.includes(location.hostname))this.track('outbound_link',{url:outbound.href});});const search=document.getElementById('search-input');if(search){let t;search.addEventListener('input',e=>{clearTimeout(t);t=setTimeout(()=>{if(e.target.value.length>=3)this.track('search',{query_length:e.target.value.length});},1000);});}},setupErrorTracking(){window.addEventListener('error',e=>{this.track('js_error',{message:e.message,file:e.filename,line:e.lineno});});window.addEventListener('unhandledrejection',e=>{this.track('promise_error',{reason:String(e.reason).substring(0,100)});});}};if(document.readyState==='loading')document.addEventListener('DOMContentLoaded',()=>A.init());else A.init();window.DCHubAnalytics=A;window.addEventListener('beforeunload',()=>{A.track('session_end',{duration:Math.round((Date.now()-A.session.startTime)/1000),pages:A.session.pageViews,chats:A.session.chatMessages,scroll:A.session.scrollDepthMax});});})();
